# Typical production configuration for a 3-stage document pipeline

STAGE_CONFIGS = {
    # Stage 1: extract entities to JSON — zero penalties mandatory
    "extract": {
        "model": "gpt-4o",
        "temperature": 0.1,
        "presence_penalty": 0.0,
        "frequency_penalty": 0.0,
        "response_format": {"type": "json_object"},
    },
    # Stage 2: prose reasoning — light penalties prevent loop echoes
    "analyse": {
        "model": "gpt-4o",
        "temperature": 0.5,
        "presence_penalty": 0.3,
        "frequency_penalty": 0.1,
    },
    # Stage 3: narrative report — stronger penalties for fresh vocabulary
    "report": {
        "model": "gpt-4o",
        "temperature": 0.7,
        "presence_penalty": 0.5,
        "frequency_penalty": 0.3,
    },
}

# WRONG: global penalty applied blindly
def call_llm(messages):
    return client.chat.completions.create(
        model="gpt-4o-mini",
        messages=messages,
        presence_penalty=0.5,   # breaks JSON steps
        frequency_penalty=0.3,
    )

# RIGHT: step-type-aware dispatch
def call_llm(messages, structured_output=False):
    return client.chat.completions.create(
        model="gpt-4o-mini",
        messages=messages,
        presence_penalty=0.0 if structured_output else 0.3,
        frequency_penalty=0.0 if structured_output else 0.1,
    )
